interface Base { id: string }
interface Timestamped extends Base { createdAt: number }

type Id = string | number          // union
type WithMeta = Timestamped & { source: string }   // intersection

function parseReply(json: string): { text: string } {
  const data: unknown = JSON.parse(json)
  if (typeof data === "object" && data !== null && "text" in data) {
    return { text: String((data as { text: unknown }).text) }
  }
  throw new Error("unexpected reply shape")
}

interface ApiResult<T> {
  data: T
  latencyMs: number
}

